use std::cmp::{max, min};

fn naive(s: String) -> i32 {
    let mut count: i32 = 0;
    let mut has_a;
    let mut has_b;
    let mut has_c;

    for i in 0..=s.len() - 3 {
        has_a = false;
        has_b = false;
        has_c = false;

        for (j, character) in s[i..].chars().enumerate() {
            has_a = has_a || character == 'a';
            has_b = has_b || character == 'b';
            has_c = has_c || character == 'c';
            if has_a && has_b && has_c {
                count += (s.len() - i - j) as i32;
                break;
            }
        }
    }
    count
}

fn sliding_window(s: String) -> i32 {
    let mut indices_a = vec![];
    let mut indices_b = vec![];
    let mut indices_c = vec![];
    let chars = s.chars().collect::<Vec<char>>();

    for (i, character) in chars.clone().iter().enumerate() {
        match character {
            'a' => indices_a.push(i),
            'b' => indices_b.push(i),
            'c' => indices_c.push(i),
            default => panic!("character other than a, b, or c encountered"),
        }
    }

    if indices_a.is_empty() || indices_b.is_empty() || indices_c.is_empty() {
        return 0;
    }

    let mut a_marker = 0;
    let mut b_marker = 0;
    let mut c_marker = 0;
    let mut i = min(
        min(indices_a[a_marker], indices_b[b_marker]),
        indices_c[c_marker],
    );
    let mut j = max(
        max(indices_a[a_marker], indices_b[b_marker]),
        indices_c[c_marker],
    );
    let mut count = s.len() - j;

    loop {
        match chars.get(i) {
            Some('a') => {
                i += 1;
                a_marker += 1;
                if (a_marker >= indices_a.len()) {
                    break;
                }
                if (indices_a[a_marker] >= i && indices_a[a_marker] <= j) {
                    count += s.len() - j;
                    continue;
                }
                j = indices_a[a_marker];
                count += s.len() - j;
            }
            Some('b') => {
                i += 1;
                b_marker += 1;
                if (b_marker >= indices_b.len()) {
                    break;
                }
                if (indices_b[b_marker] >= i && indices_b[b_marker] <= j) {
                    count += s.len() - j;
                    continue;
                }
                j = indices_b[b_marker];
                count += s.len() - j;
            }
            Some('c') => {
                i += 1;
                c_marker += 1;
                if (c_marker >= indices_c.len()) {
                    break;
                }
                if (indices_c[c_marker] >= i && indices_c[c_marker] <= j) {
                    count += s.len() - j;
                    continue;
                }
                j = indices_c[c_marker];
                count += s.len() - j;
            }
            _ => panic!("something went wrong"),
        }
    }

    count as i32
}

#[cfg(test)]
mod tests {
    use crate::numberofsubstringscontainingallthreecharacters::naive;
    use crate::numberofsubstringscontainingallthreecharacters::sliding_window;
    use rstest::rstest;

    #[rstest]
    #[case("abcabc", 10)]
    #[case("aaacb", 3)]
    #[case("abc", 1)]
    #[case(
        "",
        1247399901
    )]
    fn test_naive(#[case] input: &str, #[case] result: i32) {
        assert_eq!(naive(input.to_string()), result);
    }

    #[rstest]
    #[case("abcabc", 10)]
    #[case("aaacb", 3)]
    #[case("abc", 1)]
    #[case(
        "",
        1247399901
    )]
    fn test_sliding_window(#[case] input: &str, #[case] result: i32) {
        assert_eq!(sliding_window(input.to_string()), result);
    }
}
